import * as React from 'react';
import Box from '@mui/material/Box';
import AppBar from '@mui/material/AppBar';
import Button from '@mui/material/Button';
import Grid from '@mui/material/Grid';
import Link from '@mui/material/Link';
import { styled } from '@mui/material/styles';
import { useNavigate } from 'react-router-dom';

const LinkButton = styled(Button)(() => ({
  width: '100%',
  height: '100%',
  borderRadius: '0px',
}));

const collections = ['Daylight', 'Dust', 'Escape', 'Illusion', 'Mountains', 'Nice Dream', 'Rose Gold', 'Stay', 'Times', 'Voyages']

function SubHeader () {
  const navigate = useNavigate();

  const galleries = [];

  collections.forEach((gallery) => {
    const name = gallery.toLowerCase().trim().replace(/\s/g, '');
    galleries.push(
      <Grid item xs={1} sm={1} lg={1} sx={{ backgroundColor: '' }} key={'item_' + name}>
        <LinkButton
          onClick={() => navigate('/collections/' + name)}
          color='inherit'
          id={'button_' + name}
        >
          {gallery}
        </LinkButton>
      </Grid>
    )
  })

  const dataFetchRef = React.useRef(false);
  const [navigation, setNavigation] = React.useState([]);

  const build = () => {
    collections.forEach((gallery) => {
      setNavigation(navigation => [
        ...navigation,
        <Grid item xs={1} sm={1} lg={1} sx={{ backgroundColor: '' }} key={'item_' + gallery}>
          <LinkButton
            onClick={() => navigate('/collections/' + gallery.toLowerCase().trim().replace(/\s/g, ''))}
            color='inherit'
            key={'button_' + gallery}
          >
            {gallery}
          </LinkButton>
        </Grid>
      ])
    })
  }

  React.useEffect(() => {
    // if (dataFetchRef.current) return;
    // dataFetchRef.current = true;
    build();
  }, [])

  return (
    <>
      <AppBar
        position='static'
        color='inherit'
        sx={{
          boxShadow: '0px 0px 0px #e3e3e3',
        }}
      >
        <Box
          sx={{
            display: 'block',
            margin: '86px 10% 30px',
          }}
        >
          <Grid container columns={{ xs: 2, sm: 5, lg: 10 }} gap={0}>
            {navigation}
            {/* {galleries} */}
          </Grid>
        </Box>
      </AppBar>
    </>
  )
}

export default SubHeader;
